# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from graphene import ObjectType, String, List, Schema, Int
from graphene_sqlalchemy import SQLAlchemyObjectType
from flask_graphql import GraphQLView
from models import db_session, Product as ProductModel, Category as CategoryModel, Review as ReviewModel

class Product(SQLAlchemyObjectType):
    class Meta:
        model = ProductModel

class Category(SQLAlchemyObjectType):
    class Meta:
        model = CategoryModel

class Review(SQLAlchemyObjectType):
    class Meta:
        model = ReviewModel

class Query(ObjectType):
    products = List(Product)
    product = String(id=Int(required=True))
    categories = List(Category)
    reviews_for_product = List(Review, product_id=Int(required=True))

    def resolve_products(self, info):
        query = Product.get_query(info)  # SQLAlchemy query
        return query.all()

    def resolve_product(self, info, id):
        return ProductModel.query.get(id)

    def resolve_categories(self, info):
        query = Category.get_query(info)
        return query.all()

    def resolve_reviews_for_product(self, info, product_id):
        return ReviewModel.query.filter_by(product_id=product_id).all()

schema = Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True  # Enable for introspection during development
    )
)

if __name__ == '__main__':
    app.run(debug=True)